'use client'

import { cva } from 'class-variance-authority'
import AutoScroll from 'embla-carousel-auto-scroll'
import { motion } from 'motion/react'
import Image from 'next/image'
import { useEffect, useRef, useState } from 'react'

import {
  Carousel,
  type CarouselApi,
  CarouselContent,
  CarouselItem,
} from '@/components/ui/carousel'
import { cn } from '@/lib/utils'

export type CarouselFocusAspect = 'landscape' | 'portrait' | 'wide'

export interface CarouselFocusImage {
  url: string
  aspect: CarouselFocusAspect
}

export interface CarouselFocusItem {
  title: string
  image: CarouselFocusImage
}

export type CarouselFocusTitlePlacement = 'inside' | 'outside'

export interface CarouselFocusProps {
  titlePlacement: CarouselFocusTitlePlacement
  items: CarouselFocusItem[]
}

const aspectVariants = cva('relative w-full overflow-hidden rounded-xl', {
  variants: {
    aspect: {
      landscape: 'aspect-[17/9]',
      portrait: 'aspect-[3/2]',
      wide: 'aspect-[21/8]',
    },
  },
  defaultVariants: {
    aspect: 'landscape',
  },
})

export function CarouselFocus({
  titlePlacement,
  items,
}: Readonly<CarouselFocusProps>) {
  const [api, setApi] = useState<CarouselApi>()
  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null)
  const hoverCountRef = useRef(0)
  const resumeTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  useEffect(() => {
    if (!api) return
    const autoScroll = api.plugins()?.autoScroll
    if (autoScroll) {
      autoScroll.play()
    }
  }, [api])

  const handleItemMouseEnter = (index: number) => {
    setHoveredIndex(index)
    hoverCountRef.current += 1
    if (resumeTimeoutRef.current) {
      clearTimeout(resumeTimeoutRef.current)
      resumeTimeoutRef.current = null
    }
    api?.plugins()?.autoScroll?.stop()
  }

  const handleItemMouseLeave = () => {
    setHoveredIndex(null)
    hoverCountRef.current -= 1
    if (hoverCountRef.current <= 0) {
      hoverCountRef.current = 0
      resumeTimeoutRef.current = setTimeout(() => {
        api?.plugins()?.autoScroll?.play()
        resumeTimeoutRef.current = null
      }, 50)
    }
  }

  const titleMotionProps = {
    initial: { y: 6, opacity: 0 },
    transition: { duration: 0.2, ease: 'easeOut' as const },
  }

  if (!items?.length) return null

  return (
    <Carousel
      setApi={setApi}
      opts={{
        align: 'center',
        loop: true,
        watchDrag: false,
      }}
      plugins={[
        AutoScroll({
          speed: 1,
          startDelay: 0,
          stopOnMouseEnter: false,
          stopOnInteraction: false,
        }),
      ]}
      className="w-full"
      aria-label="Carousel de imagens"
    >
      <CarouselContent className="-ml-4">
        {items.map((item, index) => {
          const isHovered = hoveredIndex === index
          const isDimmed = hoveredIndex !== null && hoveredIndex !== index
          if (titlePlacement === 'outside') {
            return (
              <CarouselItem
                key={`${item.title}-${index}`}
                className="basis-full pl-4 md:basis-[36%]"
              >
                <button
                  type="button"
                  aria-label={item.title}
                  className={cn(
                    'flex w-full cursor-default flex-col gap-1 border-0 bg-transparent p-0 text-left transition-opacity duration-300',
                    isDimmed && 'opacity-50',
                  )}
                  onMouseEnter={() => handleItemMouseEnter(index)}
                  onMouseLeave={handleItemMouseLeave}
                  onFocus={() => handleItemMouseEnter(index)}
                  onBlur={handleItemMouseLeave}
                >
                  <motion.span
                    className="text-foreground min-h-0 overflow-hidden text-sm font-medium"
                    {...titleMotionProps}
                    animate={
                      isHovered ? { y: -5, opacity: 1 } : { y: 1, opacity: 0 }
                    }
                    transition={{ duration: 0.2, ease: 'easeInOut' }}
                  >
                    {item.title}
                  </motion.span>
                  <span
                    className={cn(
                      'relative w-full overflow-hidden rounded-xl',
                      aspectVariants({ aspect: item.image.aspect }),
                    )}
                  >
                    <Image
                      src={item.image.url}
                      alt=""
                      className="pointer-events-none object-cover"
                      fill
                      sizes="(max-width: 768px) 100vw, 40vw"
                      unoptimized
                    />
                  </span>
                </button>
              </CarouselItem>
            )
          }

          return (
            <CarouselItem
              key={`${item.title}-${index}`}
              className="basis-full pl-4 md:basis-[36%]"
            >
              <button
                type="button"
                aria-label={item.title}
                className={cn(
                  aspectVariants({ aspect: item.image.aspect }),
                  'block w-full cursor-default border-0 bg-transparent p-0 text-left transition-opacity duration-300',
                  isDimmed && 'opacity-50',
                )}
                onMouseEnter={() => handleItemMouseEnter(index)}
                onMouseLeave={handleItemMouseLeave}
                onFocus={() => handleItemMouseEnter(index)}
                onBlur={handleItemMouseLeave}
              >
                <Image
                  src={item.image.url}
                  alt=""
                  className="pointer-events-none object-cover"
                  fill
                  sizes="(max-width: 768px) 100vw, 40vw"
                  unoptimized
                />
                <motion.span
                  className="absolute right-0 bottom-0 left-0 bg-gradient-to-t from-black/50 to-transparent px-3 py-2.5 text-sm font-medium text-white"
                  {...titleMotionProps}
                  transition={{ duration: 0.2, ease: 'easeInOut' }}
                  initial={{ y: 8, opacity: 0 }}
                  animate={
                    isHovered ? { y: 0, opacity: 1 } : { y: 8, opacity: 0 }
                  }
                >
                  {item.title}
                </motion.span>
              </button>
            </CarouselItem>
          )
        })}
      </CarouselContent>
    </Carousel>
  )
}

import { CarouselFocus, type CarouselFocusProps } from './carousel-focus'

export function CarouselFocusExample() {
  const values = {
    titlePlacement: 'outside',
    items: [
      {
        title: 'Ship faster',
        image: {
          url: 'https://images.unsplash.com/photo-1610611742876-97e4d834d077?q=80&w=1170&auto=format&fit=crop',
          aspect: 'landscape',
        },
      },
      {
        title: 'Performance first',
        image: {
          url: 'https://images.unsplash.com/photo-1688327009265-3e47cdab9dc4?q=80&w=1169&auto=format&fit=crop',
          aspect: 'portrait' as const,
        },
      },
      {
        title: 'Stay in control',
        image: {
          url: 'https://images.unsplash.com/photo-1610210162763-6c4d6da47c8f?q=80&w=1170&auto=format&fit=crop',
          aspect: 'landscape' as const,
        },
      },
      {
        title: 'Built together',
        image: {
          url: 'https://images.unsplash.com/photo-1672917765736-c1c397a5d37f?q=80&w=1170&auto=format&fit=crop',
          aspect: 'portrait' as const,
        },
      },
    ],
  } satisfies CarouselFocusProps

  return (
    <CarouselFocus
      titlePlacement={values.titlePlacement}
      items={values.items}
    />
  )
}
